#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> floodFill(vector<vector<int>>& image, int sr, int sc, int newColor) {
        int old_color = image[sr][sc];
        if (old_color == newColor) return image;
        dfs(image, sr, sc, old_color, newColor);
        return image;
    }

    void dfs(vector<vector<int>>& image, int r, int c, int old_color, int new_color) {
        if (r >= 0 && r < image.size() && c >= 0 && c < image[0].size() && image[r][c] == old_color) {
            image[r][c] = new_color;
            dfs(image, r - 1, c, old_color, new_color);
            dfs(image, r + 1, c, old_color, new_color);
            dfs(image, r, c - 1, old_color, new_color);
            dfs(image, r, c + 1, old_color, new_color);
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n, sr, sc, newColor;
    cin >> m >> n >> sr >> sc >> newColor;
    vector<vector<int>> image(m, vector<int>(n));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            cin >> image[i][j];
        }
    }
    Solution sol;
    vector<vector<int>> ans = sol.floodFill(image, sr, sc, newColor);
    for (const auto& row : ans) {
        for (int val : row) {
            cout << val << " ";
        }
        cout << "\n";
    }
    return 0;
}
